167	  display: "grid",
168	  gap: "var(--space-sm)",
169	};
170	
171	const commentListStyle: React.CSSProperties = {
172	  display: "grid",
173	  gap: "var(--space-sm)",
174	};
175	
176	const commentCardStyle: React.CSSProperties = {
177	  borderRadius: "var(--radius-sm)",
178	  border: "1px solid var(--color-border)",
179	  background: "var(--color-bg)",
180	  padding: "var(--space-sm) var(--space-md)",
181	  display: "grid",
182	  gap: "var(--space-xs)",
183	};
184	
