242	  padding: "8px 14px",
243	  borderRadius: "var(--radius-sm)",
244	  border: "none",
245	  background: "var(--color-primary)",
246	  color: "#fff",
247	  fontWeight: 600,
248	  fontSize: "0.85rem",
249	};
