252	  padding: "var(--space-sm) var(--space-md)",
253	  borderRadius: "var(--radius-sm)",
254	  border: "1px dashed var(--color-border)",
255	  color: "var(--color-text-muted)",
256	  background: "rgba(15, 23, 42, 0.02)",
257	  fontSize: "0.85rem",
258	};
